SELECT [Purchase Header].[Buy-from Vendor No_], Vendor.[Old Febos No_], Vendor.[Old Bridge No_], Vendor.Name, [Purchase Header].[Old Order No_], [Purchase Line].[Document No_] AS OrderNO, [Purchase Header].[Vendor Order No_], [Purchase Line].[Original Line No_], [Purchase Line].[Line No_], [Purchase Header].[Order Date] AS OrderDate, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Purchase Line].[Delete Reason], [Purchase Line].No_ AS Article, [Purchase Line].[Model Item No_], Item.[Description 2] AS Description, Item_1.[Description 2], [Purchase Line].[Variable Code 01] AS Color, [Variable Code].Description AS ColorDescription, qSoloAcqItemDeterminazioneNumeroAssortimenti.AssortmentCode, qSoloAcqItemDeterminazioneNumeroAssortimenti.NumeroAssortimenti, [Purchase Line].[Variable Code 02] AS [Size], Val([quantity]) AS Pairs, [Purchase Header].[Document Type], [Purchase Line].[Currency Code], Val([Purchase Line.Quantity]) AS QuantityPurchased, Val([Purchase Line.No_ of Pairs]) AS PairsPurchased, Val([purchase line.line amount]) AS ValuePurchased, Val([Purchase Line.Quantity Received]) AS QuantityReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsReceived, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueReceived, Val([Purchase Line.Quantity Invoiced]) AS QuantityInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0) AS PairsInvoicedPurchases, IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity invoiced])/Val([Purchase Line.quantity])*Val([purchase line.line amount]),0) AS ValueInvoicedPurchases, [Purchase Line].[Requested Receipt Date], [Purchase Line].[Promised Receipt Date], [Purchase Line].[Expected Receipt Date], Item.[Country_Region of Origin Code], Item.[Tariff No_]
FROM ((((([Purchase Header] INNER JOIN [Purchase Line] ON ([Purchase Header].No_ = [Purchase Line].[Document No_]) AND ([Purchase Header].[Document Type] = [Purchase Line].[Document Type])) INNER JOIN Item ON [Purchase Line].No_ = Item.No_) INNER JOIN [Variable Code] ON ([Purchase Line].[Variable Code 01] = [Variable Code].[Variable Code]) AND ([Purchase Line].[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN Vendor ON [Purchase Header].[Buy-from Vendor No_] = Vendor.No_) INNER JOIN qSoloAcqItemDeterminazioneNumeroAssortimenti ON ([Purchase Line].[Original Line No_] = qSoloAcqItemDeterminazioneNumeroAssortimenti.[Line No_]) AND ([Purchase Line].[Document No_] = qSoloAcqItemDeterminazioneNumeroAssortimenti.[Document No_])) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_
WHERE ((([Purchase Header].[Document Type])=1) AND (([Purchase Line].Type)=2));

